// Story 3: painterMouse (colour-spelling)
S['painterMouse'] = {
  ar: ['الفأر الرسام','اكتشف فأر صغير فراشي سحرية! فقدت الورود لونها. ما اللون الذي يجب أن تكون عليه؟','أمسك الفأر بالفرشاة التالية. يجب أن يكون ___ بلون ___ مرة أخرى!','أزهار الكرز تحتاج لونها الجميل! لوّح الفأر بالفرشاة وانتظر الكلمة السحرية.','صندوق الكنز يحتاج بريق ___، مثل ___ المتلألئ فوق!','الفرشاة الأخيرة! الجدار الحجري القديم يحتاج لونه. رسم الفأر آخر لمسة — العالم جميل مرة أخرى!'],
  da: ['Malermusen','En lille mus opdager magiske pensler! Roserne har mistet deres farve. Hvilken farve skal de være?','Musen tager den næste pensel. ___ skal være ___ igen!','Kirsebærblomstrene har brug for deres smukke farve tilbage! Musen vifter med penslen og venter på det magiske ord.','Skattekisten har brug for en ___ glans, som den ___ der skinner ovenover!','Den sidste pensel! Den gamle stenmur har brug for sin farve. Musen maler det sidste strøg — verden er smuk igen!'],
  de: ['Die Malermaus','Eine kleine Maus entdeckt magische Pinsel! Die Rosen haben ihre Farbe verloren. Welche Farbe sollten sie haben?','Maus nimmt den nächsten Pinsel. Der ___ soll wieder ___ sein!','Die Kirschblüten brauchen ihre schöne Farbe zurück! Maus wedelt mit dem Pinsel und wartet auf das Zauberwort.','Die Schatztruhe braucht einen ___ Schimmer, wie der ___ der oben scheint!','Der letzte Pinsel! Die alte Steinmauer braucht ihre Farbe. Maus malt den letzten Strich — die Welt ist wieder schön!'],
  es: ['El Ratón Pintor','¡Un ratoncito descubre pinceles mágicos! Las rosas han perdido su color. ¿Qué color deberían tener?','El ratón toma el siguiente pincel. ¡El ___ debería ser ___ de nuevo!','¡Los cerezos necesitan su hermoso color! El ratón agita el pincel y espera la palabra mágica.','¡El cofre del tesoro necesita un brillo ___, como el ___ que brilla arriba!','¡El último pincel! El viejo muro de piedra necesita su color. El ratón pinta la última pincelada — ¡el mundo es hermoso otra vez!'],
  fr: ['La Souris Peintre','Une petite souris découvre des pinceaux magiques ! Les roses ont perdu leur couleur. Quelle couleur devraient-elles être ?','La souris prend le pinceau suivant. Le ___ devrait être ___ à nouveau !','Les cerisiers en fleurs ont besoin de leur belle couleur ! La souris agite le pinceau et attend le mot magique.','Le coffre au trésor a besoin d\\\'un éclat ___, comme le ___ qui brille au-dessus !','Le dernier pinceau ! Le vieux mur de pierre a besoin de sa couleur. La souris peint le dernier trait — le monde est beau à nouveau !'],
  it: ['Il Topo Pittore','Un topolino scopre pennelli magici! Le rose hanno perso il loro colore. Di che colore dovrebbero essere?','Il topo prende il pennello successivo. Il ___ dovrebbe essere di nuovo ___!','I fiori di ciliegio hanno bisogno del loro bel colore! Il topo agita il pennello e aspetta la parola magica.','Il forziere ha bisogno di un bagliore ___, come il ___ che brilla sopra!','L\\\'ultimo pennello! Il vecchio muro di pietra ha bisogno del suo colore. Il topo dipinge l\\\'ultimo tratto — il mondo è di nuovo bello!'],
  ja: ['えかきネズミ','ちいさなネズミがまほうのふでをみつけた！バラがいろをうしなってしまいました。なにいろにすればいい？','ネズミはつぎのふでをとりました。___はまた___になるべきだ！','さくらのはなにきれいないろがもどらないと！ネズミがふでをふって、まほうのことばをまちます。','たからばこには___のかがやきがひつよう、うえでひかる___みたいに！','さいごのふで！ふるいいしかべにいろがひつよう。ネズミがさいごのひとぬり — せかいはまたきれいになった！'],
  la: ['Mus Pictor','Parvus mus penicillos magicos invenit! Rosae colorem amiserunt. Quis color esse debent?','Mus proximum penicillum sumit. ___ iterum ___ esse debet!','Flores cerasi pulchrum colorem recuperare debent! Mus penicillum agitat et verbum magicum exspectat.','Arca thesauri splendorem ___ eget, sicut ___ supra fulgens!','Ultimus penicillus! Vetus murus lapideus colorem suum eget. Mus ultimum ictum pingit — mundus iterum pulcher est!'],
  nl: ['De Schildermuis','Een klein muisje ontdekt magische penselen! De rozen hebben hun kleur verloren. Welke kleur moeten ze zijn?','Muis pakt het volgende penseel. De ___ moet weer ___ worden!','De kersenbloesems hebben hun mooie kleur nodig! Muis zwaait met het penseel en wacht op het toverwoord.','De schatkist heeft een ___ glans nodig, zoals de ___ die erboven schijnt!','Het laatste penseel! De oude stenen muur heeft zijn kleur nodig. Muis schildert de laatste streek — de wereld is weer mooi!'],
  pl: ['Mysz Malarz','Mała myszka odkrywa magiczne pędzle! Róże straciły kolor. Jaki kolor powinny mieć?','Myszka bierze następny pędzel. ___ powinien znów być ___!','Kwiaty wiśni potrzebują swojego pięknego koloru! Myszka macha pędzlem i czeka na magiczne słowo.','Skrzynia ze skarbem potrzebuje ___ blasku, jak ___ świecący w górze!','Ostatni pędzel! Stary kamienny mur potrzebuje koloru. Myszka maluje ostatnie pociągnięcie — świat jest znów piękny!'],
  pt: ['O Rato Pintor','Um ratinho descobre pincéis mágicos! As rosas perderam sua cor. Que cor deveriam ter?','O rato pega o próximo pincel. O ___ deveria ser ___ novamente!','As flores de cerejeira precisam de sua bela cor! O rato agita o pincel e espera a palavra mágica.','O baú do tesouro precisa de um brilho ___, como o ___ brilhando lá em cima!','O último pincel! O velho muro de pedra precisa de sua cor. O rato pinta a última pincelada — o mundo está bonito novamente!'],
  tr: ['Ressam Fare','Küçük bir fare sihirli fırçalar keşfeder! Güller renklerini kaybetmiş. Ne renk olmalılar?','Fare sonraki fırçayı alır. ___ tekrar ___ olmalı!','Kiraz çiçekleri güzel renklerini geri istiyor! Fare fırçayı sallar ve sihirli kelimeyi bekler.','Hazine sandığı bir ___ parıltısına ihtiyaç duyuyor, yukarıda parlayan ___ gibi!','Son fırça! Eski taş duvarın rengine ihtiyacı var. Fare son darbeyi vurur — dünya yine güzel!'],
  zh: ['画家小老鼠','一只小老鼠发现了魔法画笔！玫瑰失去了颜色。它们应该是什么颜色？','小老鼠拿起下一支画笔。___应该重新变成___！','樱花需要恢复美丽的颜色！小老鼠挥动画笔，等待魔法词语。','宝箱需要___的光芒，就像上面闪耀的___一样！','最后一支画笔！古老的石墙需要它的颜色。小老鼠画下最后一笔——世界又变得美丽了！'],
};

// Story 4: shapesInClouds (shape-spelling)
S['shapesInClouds'] = {
  ar: ['أشكال في الغيوم','استلقى الأرنب على العشب ونظر للأعلى. الغيوم تشكل أشكالاً! هل تراها أيضاً؟','هذه الغيمة تبدو مثل ___! دائرية ___. هل يمكنك تهجئة الشكل؟','الريح تهب وتتغير الغيوم. الآن هناك شيء بأربع زوايا!','بالقرب من الشمس، ___ بثلاثة أضلاع يتلألأ مثل ___.','أبتسم الأرنب. الغيوم تصنع أجمل الأشكال! أي شكل تراه أنت؟'],
  da: ['Former i skyerne','Kanin lagde sig i græsset og kiggede op. Skyerne danner former! Kan du også se dem?','Den sky ligner en ___! Rund og ___. Kan du stave formen?','Vinden blæser og skyerne ændrer sig. Nu er der noget med fire hjørner!','Nær solen glitrer en ___ med tre sider som en ___.','Kanin smilede. Skyerne laver de smukkeste former! Hvilken form kan du se?'],
  de: ['Formen in den Wolken','Hase legte sich ins Gras und schaute nach oben. Die Wolken bilden Formen! Siehst du sie auch?','Diese Wolke sieht aus wie ein ___! Rund und ___. Kannst du die Form buchstabieren?','Der Wind bläst und die Wolken verändern sich. Jetzt gibt es etwas mit vier Ecken!','Nahe der Sonne glitzert ein ___ mit drei Seiten wie ein ___.','Hase lächelte. Die Wolken machen die schönsten Formen! Welche Form siehst du?'],
  es: ['Formas en las nubes','Conejo se acostó en la hierba y miró hacia arriba. ¡Las nubes forman figuras! ¿Tú también las ves?','¡Esa nube parece un ___! Redonda y ___. ¿Puedes deletrear la forma?','El viento sopla y las nubes cambian. ¡Ahora hay algo con cuatro esquinas!','Cerca del sol, un ___ con tres lados brilla como un ___.','Conejo sonrió. ¡Las nubes hacen las formas más bonitas! ¿Qué forma ves tú?'],
  fr: ['Formes dans les nuages','Lapin s\\\'est allongé dans l\\\'herbe et a regardé en haut. Les nuages forment des formes ! Les vois-tu aussi ?','Ce nuage ressemble à un ___ ! Rond et ___. Peux-tu épeler la forme ?','Le vent souffle et les nuages changent. Maintenant il y a quelque chose avec quatre coins !','Près du soleil, un ___ à trois côtés scintille comme un ___.','Lapin a souri. Les nuages font les plus belles formes ! Quelle forme vois-tu ?'],
  it: ['Forme nelle nuvole','Coniglio si è sdraiato sull\\\'erba e ha guardato in alto. Le nuvole formano delle forme! Le vedi anche tu?','Quella nuvola sembra un ___! Rotonda e ___. Sai sillabare la forma?','Il vento soffia e le nuvole cambiano. Ora c\\\'è qualcosa con quattro angoli!','Vicino al sole, un ___ con tre lati brilla come un ___.','Coniglio ha sorriso. Le nuvole fanno le forme più belle! Quale forma vedi tu?'],
  ja: ['くものなかのかたち','うさぎがくさのうえにねころんで、うえをみました。くもがかたちをつくっている！きみにもみえる？','このくもは___みたい！まるくて___。かたちをつづれるかな？','かぜがふいて、くもがかわります。いまよつのかどがあるものがみえるよ！','たいようのそばで、みっつのへんがある___が___のようにきらきらしています。','うさぎはにっこりしました。くもはいちばんきれいなかたちをつくるね！きみにはなにがみえる？'],
  la: ['Formae in nubibus','Lepus in herba iacuit et sursum spectavit. Nubes formas faciunt! Videsne eas quoque?','Illa nubes ___ similis est! Rotunda et ___. Potesne formam litteris ponere?','Ventus flat et nubes mutantur. Nunc aliquid cum quattuor angulis est!','Prope solem, ___ tribus lateribus sicut ___ scintillat.','Lepus subrisit. Nubes pulcherrimas formas faciunt! Quam formam vides?'],
  nl: ['Vormen in de wolken','Konijn ging in het gras liggen en keek omhoog. De wolken maken vormen! Zie jij ze ook?','Die wolk lijkt op een ___! Rond en ___. Kun je de vorm spellen?','De wind blaast en de wolken veranderen. Nu is er iets met vier hoeken!','Dicht bij de zon glinstert een ___ met drie zijden als een ___.','Konijn glimlachte. De wolken maken de mooiste vormen! Welke vorm zie jij?'],
  pl: ['Kształty w chmurach','Królik położył się na trawie i spojrzał w górę. Chmury tworzą kształty! Czy ty też je widzisz?','Ta chmura wygląda jak ___! Okrągła i ___. Czy potrafisz przeliterować kształt?','Wiatr wieje i chmury się zmieniają. Teraz jest coś z czterema rogami!','Blisko słońca ___ o trzech bokach lśni jak ___.','Królik się uśmiechnął. Chmury tworzą najpiękniejsze kształty! Jaki kształt widzisz ty?'],
  pt: ['Formas nas nuvens','Coelho deitou na grama e olhou para cima. As nuvens formam figuras! Você também as vê?','Aquela nuvem parece um ___! Redonda e ___. Você sabe soletrar a forma?','O vento sopra e as nuvens mudam. Agora tem algo com quatro cantos!','Perto do sol, um ___ com três lados brilha como um ___.','Coelho sorriu. As nuvens fazem as formas mais bonitas! Que forma você vê?'],
  tr: ['Bulutlardaki Şekiller','Tavşan çimenlere uzandı ve yukarı baktı. Bulutlar şekiller oluşturuyor! Sen de görüyor musun?','O bulut bir ___ gibi görünüyor! Yuvarlak ve ___. Şekli heceleyebilir misin?','Rüzgâr esiyor ve bulutlar değişiyor. Şimdi dört köşeli bir şey var!','Güneşin yanında, üç kenarlı bir ___ bir ___ gibi parlıyor.','Tavşan gülümsedi. Bulutlar en güzel şekilleri yapıyor! Sen hangi şekli görüyorsun?'],
  zh: ['云中的形状','兔子躺在草地上抬头看。云朵在变成各种形状！你也看到了吗？','那朵云看起来像一个___！圆圆的___。你能拼写这个形状吗？','风吹来，云朵变了。现在有个四个角的东西！','太阳旁边，一个有三条边的___像___一样闪闪发光。','兔子笑了。云朵做出最美的形状！你看到了什么形状？'],
};

// Story 5: firstDayFriends (first-words)
S['firstDayFriends'] = {
  ar: ['أصدقاء اليوم الأول','اليوم هو أول يوم في المدرسة! وصل طفل صغير حاملاً ___ مليء بالمفاجآت.','في الفصل، هناك ___ ملونة على كل طاولة. هل يمكنك تهجئة ما تراه؟','وقت اللعب! في الخارج هناك ___ كبير يلمع تحت ___. يا له من يوم رائع!','صديق جديد يشارك ___. يا لها من لفتة لطيفة! هل يمكنك تهجئة ما شاركه؟','نهاية يوم سعيد! الجميع يلوح بـ___. أول يوم كان مليئاً بالأصدقاء الجدد!'],
  da: ['Første dags venner','I dag er det første skoledag! Et lille barn ankom med en ___ fuld af overraskelser.','I klasseværelset er der farverige ___ på hvert bord. Kan du stave hvad du ser?','Leg! Udenfor er der en stor ___ der skinner under ___. Sikke en dag!','En ny ven deler sin ___. Hvor sødt! Kan du stave hvad der blev delt?','Slutningen på en glad dag! Alle vinker med ___. Første dag var fuld af nye venner!'],
  de: ['Freunde am ersten Tag','Heute ist der erste Schultag! Ein kleines Kind kam mit einer ___ voller Überraschungen.','Im Klassenzimmer sind bunte ___ auf jedem Tisch. Kannst du buchstabieren was du siehst?','Spielzeit! Draußen gibt es einen großen ___ der unter ___ glänzt. Was für ein Tag!','Ein neuer Freund teilt sein ___. Wie nett! Kannst du buchstabieren was geteilt wurde?','Ende eines glücklichen Tages! Alle winken mit ___. Der erste Tag war voller neuer Freunde!'],
  es: ['Amigos del primer día','¡Hoy es el primer día de escuela! Un niño pequeño llegó con una ___ llena de sorpresas.','En el aula hay ___ coloridos en cada mesa. ¿Puedes deletrear lo que ves?','¡Hora de jugar! Afuera hay un gran ___ brillando bajo el ___. ¡Qué día!','Un nuevo amigo comparte su ___. ¡Qué amable! ¿Puedes deletrear lo que compartió?','¡Fin de un día feliz! Todos saludan con ___. ¡El primer día estuvo lleno de nuevos amigos!'],
  fr: ['Amis du premier jour','Aujourd\\\'hui c\\\'est le premier jour d\\\'école ! Un petit enfant est arrivé avec un ___ plein de surprises.','Dans la classe, il y a des ___ colorés sur chaque table. Peux-tu épeler ce que tu vois ?','Récréation ! Dehors il y a un grand ___ qui brille sous le ___. Quelle journée !','Un nouvel ami partage son ___. Comme c\\\'est gentil ! Peux-tu épeler ce qu\\\'il a partagé ?','Fin d\\\'une journée heureuse ! Tout le monde fait au revoir avec ___. Le premier jour était plein de nouveaux amis !'],
  it: ['Amici del primo giorno','Oggi è il primo giorno di scuola! Un bambino è arrivato con uno ___ pieno di sorprese.','In classe ci sono ___ colorati su ogni tavolo. Sai sillabare quello che vedi?','Ricreazione! Fuori c\\\'è un grande ___ che brilla sotto il ___. Che giornata!','Un nuovo amico condivide il suo ___. Che gentile! Sai sillabare cosa ha condiviso?','Fine di una giornata felice! Tutti salutano con ___. Il primo giorno era pieno di nuovi amici!'],
  ja: ['はじめてのともだち','きょうはがっこうのはじめてのひ！ちいさなこどもが___いっぱいのサプライズをもってやってきました。','きょうしつでは、テーブルごとにカラフルな___があります。なにがみえるかつづれるかな？','あそびのじかん！そとにはおおきな___が___のしたでひかっています。すてきないちにち！','あたらしいともだちが___をわけてくれました。やさしいね！なにをわけたかつづれるかな？','たのしいいちにちのおわり！みんなが___でてをふっています。はじめてのひはあたらしいともだちでいっぱいでした！'],
  la: ['Amici primi diei','Hodie est primus dies scholae! Parvus puer cum ___ plena mirabilium advenit.','In schola, ___ colorata in omni mensa sunt. Potesne quod vides litteris ponere?','Tempus ludendi! Foris magnus ___ sub ___ fulget. Qualis dies!','Novus amicus ___ suum communicat. Quam benignum! Potesne quod communicavit litteris ponere?','Finis diei laeti! Omnes ___ salutant. Primus dies plenus novis amicis erat!'],
  nl: ['Vrienden op de eerste dag','Vandaag is de eerste schooldag! Een klein kind kwam aan met een ___ vol verrassingen.','In de klas staan kleurrijke ___ op elke tafel. Kun je spellen wat je ziet?','Speeltijd! Buiten is er een grote ___ die glanst onder de ___. Wat een dag!','Een nieuwe vriend deelt zijn ___. Wat lief! Kun je spellen wat er gedeeld werd?','Einde van een fijne dag! Iedereen zwaait met ___. De eerste dag zat vol nieuwe vrienden!'],
  pl: ['Przyjaciele pierwszego dnia','Dziś jest pierwszy dzień szkoły! Małe dziecko przyszło z ___ pełnym niespodzianek.','W klasie na każdym stoliku są kolorowe ___. Czy potrafisz przeliterować co widzisz?','Czas na zabawę! Na dworze jest duży ___ lśniący pod ___. Co za dzień!','Nowy przyjaciel dzieli się swoim ___. Jak miło! Czy potrafisz przeliterować czym się podzielił?','Koniec szczęśliwego dnia! Wszyscy machają ___. Pierwszy dzień był pełen nowych przyjaciół!'],
  pt: ['Amigos do primeiro dia','Hoje é o primeiro dia de escola! Uma criança chegou com uma ___ cheia de surpresas.','Na sala de aula tem ___ coloridos em cada mesa. Você sabe soletrar o que vê?','Hora de brincar! Lá fora tem um grande ___ brilhando sob o ___. Que dia!','Um novo amigo compartilha seu ___. Que gentil! Você sabe soletrar o que foi compartilhado?','Fim de um dia feliz! Todos acenam com ___. O primeiro dia foi cheio de novos amigos!'],
  tr: ['İlk Gün Arkadaşları','Bugün okulun ilk günü! Küçük bir çocuk sürprizlerle dolu bir ___ ile geldi.','Sınıfta her masada renkli ___ var. Gördüğünü heceleyebilir misin?','Oyun zamanı! Dışarıda ___\'ın altında parlayan büyük bir ___ var. Ne güzel bir gün!','Yeni bir arkadaş ___\'ını paylaşıyor. Ne tatlı! Paylaşılan şeyi heceleyebilir misin?','Mutlu bir günün sonu! Herkes ___ ile el sallıyor. İlk gün yeni arkadaşlarla doluydu!'],
  zh: ['第一天的朋友','今天是上学的第一天！一个小朋友带着装满惊喜的___来了。','教室里每张桌子上都有彩色的___。你能拼写你看到的东西吗？','游戏时间！外面有一个大大的___在___下面闪闪发光。多棒的一天！','一个新朋友分享了他的___。真好！你能拼写他分享的东西吗？','快乐的一天结束了！大家都在挥着___。第一天充满了新朋友！'],
};

// Story 6: wombatStars
S['wombatStars'] = {
  ar: ['وومبات يعد النجوم','عندما تغيب الشمس خلف التلال، يصعد وومبات إلى مكانه المفضل. ضوء كبير مستدير متوهج يظهر في السماء. ما هو؟','ينظر وومبات للأعلى. ___ صغير يتلألأ في ___. يبدأ في ___!','شكل ناعم رقيق ينجرف عبر السماء، يخفي ضوء القمر للحظة. ما هو؟','عيون وومبات تثقل. لديه أجمل ___. يشعر بالـ___ والأمان، ملفوفاً في ___ مريح.','في حلمه، يلتقي وومبات بصديق ناعم محبوب يعطيه عناقاً دافئاً. يا له من مخلوق ودود!'],
  da: ['Wombat tæller stjernerne','Da solen dykker bag bakkerne, klatrer Wombat op til sit yndlingssted. Et stort rundt lysende lys dukker op på himlen. Hvad er det?','Wombat kigger op. En lille ___ blinker i ___. Den begynder at ___!','En blød, dunblød form driver over himlen og skjuler månelyset et øjeblik. Hvad er det?','Wombats øjne bliver tunge. Han har den mest vidunderlige ___. Han føler sig ___ og tryg, svøbt i en hyggelig ___.','I sin drøm møder Wombat en blød, krammevenlig ven som giver ham et varmt kram. Sikke et venligt væsen!'],
  de: ['Wombat zählt die Sterne','Als die Sonne hinter den Hügeln versinkt, klettert Wombat auf seinen Lieblingsplatz. Ein großes, rundes, leuchtendes Licht erscheint am Himmel. Was ist es?','Wombat schaut nach oben. Ein kleiner ___ funkelt im ___. Es beginnt zu ___!','Eine weiche, flauschige Form treibt über den Himmel und verbirgt das Mondlicht für einen Moment. Was ist es?','Wombats Augen werden schwer. Er hat den wunderbarsten ___. Er fühlt sich ___ und sicher, eingewickelt in ein gemütliches ___.','In seinem Traum trifft Wombat einen weichen, kuschligen Freund, der ihm eine warme Umarmung gibt. Was für ein freundliches Wesen!'],
  es: ['Wombat cuenta las estrellas','Cuando el sol se pone tras las colinas, Wombat sube a su mirador favorito. Una luz grande, redonda y brillante aparece en el cielo. ¿Qué es?','Wombat mira hacia arriba. Una pequeña ___ brilla en el ___. ¡Empieza a ___!','Una forma suave y esponjosa cruza el cielo, ocultando la luz de la luna por un momento. ¿Qué es?','Los ojos de Wombat se ponen pesados. Tiene el más maravilloso ___. Se siente ___ y seguro, envuelto en un acogedor ___.','En su sueño, Wombat conoce a un amigo suave y tierno que le da un abrazo cálido. ¡Qué criatura tan amigable!'],
  fr: ['Wombat compte les étoiles','Quand le soleil se couche derrière les collines, Wombat grimpe à son endroit préféré. Une grande lumière ronde et brillante apparaît dans le ciel. Qu\\\'est-ce que c\\\'est ?','Wombat regarde en haut. Une petite ___ scintille dans le ___. Elle commence à ___ !','Une forme douce et duveteuse dérive dans le ciel, cachant le clair de lune un instant. Qu\\\'est-ce que c\\\'est ?','Les yeux de Wombat deviennent lourds. Il fait le plus merveilleux ___. Il se sent ___ et en sécurité, enveloppé dans un ___ douillet.','Dans son rêve, Wombat rencontre un ami doux et câlin qui lui fait un gros câlin. Quelle créature amicale !'],
  it: ['Wombat conta le stelle','Quando il sole tramonta dietro le colline, Wombat sale al suo punto preferito. Una grande luce rotonda e luminosa appare nel cielo. Cos\\\'è?','Wombat guarda in alto. Una piccola ___ luccica nel ___. Comincia a ___!','Una forma morbida e soffice fluttua nel cielo, nascondendo il chiaro di luna per un momento. Cos\\\'è?','Gli occhi di Wombat si appesantiscono. Ha il più meraviglioso ___. Si sente ___ e al sicuro, avvolto in un accogliente ___.','Nel suo sogno, Wombat incontra un amico morbido e coccoloso che gli dà un abbraccio caldo. Che creatura amichevole!'],
  ja: ['ウォンバットがほしをかぞえる','たいようがおかのむこうにしずむと、ウォンバットはおきにいりのばしょにのぼります。おおきくてまるいひかりがそらにあらわれました。なにかな？','ウォンバットがみあげます。ちいさな___が___のなかできらきらしています。___はじめた！','やわらかくてふわふわのかたちがそらをただよって、つきのひかりをいっしゅんかくします。なにかな？','ウォンバットのめがおもくなります。いちばんすばらしい___をみます。___であんぜんなきもちで、ここちよい___につつまれています。','ゆめのなかで、ウォンバットはやわらかくてだきしめたいともだちにあいます。あたたかいハグをしてくれます。なんてやさしいいきもの！'],
  la: ['Wombat stellas numerat','Cum sol post colles descendit, Wombat ad locum dilectum ascendit. Magna rotunda lucens lux in caelo apparet. Quid est?','Wombat sursum spectat. Parva ___ in ___ scintillat. ___ incipit!','Mollis lanuginosa forma per caelum fluit, lunam momentaneam celans. Quid est?','Oculi Wombat graves fiunt. Mirabilissimum ___ habet. Se ___ et tutum sentit, in commodo ___ involutus.','In somnio, Wombat mollem amicum amplexantem calidum obviam dat. Quam amica creatura!'],
  nl: ['Wombat telt de sterren','Als de zon achter de heuvels zakt, klimt Wombat naar zijn favoriete plek. Een groot, rond, gloeiend licht verschijnt aan de hemel. Wat is het?','Wombat kijkt omhoog. Een klein ___ twinkelt in de ___. Het begint te ___!','Een zachte, donzige vorm drijft over de hemel en verbergt het maanlicht even. Wat is het?','Wombats ogen worden zwaar. Hij heeft de mooiste ___. Hij voelt zich ___ en veilig, gewikkeld in een gezellig ___.','In zijn droom ontmoet Wombat een zacht, knuffelig vriendje dat hem een warme knuffel geeft. Wat een vriendelijk beestje!'],
  pl: ['Wombat liczy gwiazdy','Gdy słońce zachodzi za wzgórzami, Wombat wspina się na swoje ulubione miejsce. Duże, okrągłe, świecące światło pojawia się na niebie. Co to jest?','Wombat patrzy w górę. Mała ___ migocze w ___. Zaczyna ___!','Miękki, puszysty kształt dryfuje po niebie, na chwilę zasłaniając światło księżyca. Co to jest?','Oczy Wombata ciężkieją. Ma najwspanialszy ___. Czuje się ___ i bezpiecznie, owinięty w przytulny ___.','We śnie Wombat spotyka miękkiego, przytulnego przyjaciela, który daje mu ciepły uścisk. Co za przyjazne stworzenie!'],
  pt: ['Wombat conta as estrelas','Quando o sol se põe atrás das colinas, Wombat sobe ao seu lugar favorito. Uma luz grande, redonda e brilhante aparece no céu. O que é?','Wombat olha para cima. Uma pequena ___ brilha no ___. Começa a ___!','Uma forma macia e fofinha flutua pelo céu, escondendo a luz da lua por um momento. O que é?','Os olhos de Wombat ficam pesados. Ele tem o mais maravilhoso ___. Se sente ___ e seguro, enrolado em um aconchegante ___.','No seu sonho, Wombat encontra um amigo macio e fofinho que lhe dá um abraço quentinho. Que criatura amigável!'],
  tr: ['Wombat Yıldızları Sayıyor','Güneş tepelerin arkasına battığında, Wombat en sevdiği yere tırmanır. Gökyüzünde büyük, yuvarlak, parlayan bir ışık belirir. Ne bu?','Wombat yukarı bakar. Küçük bir ___ ___\'da parıldar. ___ başlar!','Yumuşak, kabarık bir şekil gökyüzünde süzülerek ay ışığını bir anlığına gizler. Ne bu?','Wombat\\\'ın gözleri ağırlaşır. En harika ___\'ı görür. Kendini ___ ve güvende hisseder, rahat bir ___\'a sarılır.','Rüyasında Wombat, ona sıcak bir sarılma veren yumuşak, sevimli bir arkadaşla karşılaşır. Ne kadar dostça bir yaratık!'],
  zh: ['袋熊数星星','太阳落到山丘后面，袋熊爬上他最喜欢的地方。天空中出现了一个又大又圆又亮的光。那是什么？','袋熊抬头看。一颗小小的___在___中闪烁。开始___了！','一个柔软蓬松的形状飘过天空，暂时遮住了月光。那是什么？','袋熊的眼睛变得沉重。他做了最美好的___。他感到___和安全，裹在舒适的___里。','在梦里，袋熊遇到了一个柔软可爱的朋友，给了他一个温暖的拥抱。多么友好的小动物！'],
};

// Story 7: jungleWelcome
S['jungleWelcome'] = {
  ar: ['الغابة ترحب بك','تدخل الغابة وتسمع صوت طقطقة لطيف. من بين الأشجار، يظهر مخلوق رائع بعرف متدفق!','على ___، ___ بيضاء رقيقة تقضم ___ في أشعة الشمس!','العشب الطويل يتحرك. أذنان بخطوط سوداء وبيضاء تظهران. يا لها من أنماط مذهلة!','___ لطيف يجلس يأكل ___ عالياً في ___.',   'عالياً في شجرة الكينا، شخص رمادي ورقيق يأخذ قيلولة. تهجّ اسمه!'],
  da: ['Junglen byder dig velkommen','Du træder ind i junglen og hører en blid klip-klap lyd. Gennem træerne dukker et pragtfuldt væsen med en bølgende manke op!','På ___ nipper fluffy hvide ___ i ___!','Det høje græs rasler. To ører med sorte og hvide striber dukker op. Sikke et slående mønster!','En blid ___ sidder og spiser en ___ højt oppe i et ___.','Højt oppe i et eukalyptustræ tager en grå og dunblød en lur. Stav deres navn!'],
  de: ['Der Dschungel heißt dich willkommen','Du betrittst den Dschungel und hörst ein sanftes Klipp-Klapp. Zwischen den Bäumen erscheint ein prächtiges Wesen mit wallender Mähne!','Auf der ___ knabbern flauschige weiße ___ in der Sonne!','Das hohe Gras raschelt. Zwei Ohren mit schwarzweißen Streifen tauchen auf. Was für ein auffälliges Muster!','Ein sanfter ___ sitzt und isst eine ___ hoch oben in einem ___.','Hoch oben in einem Eukalyptusbaum macht jemand Graues und Flauschiges ein Nickerchen. Buchstabiere seinen Namen!'],
  es: ['La selva te da la bienvenida','Entras en la selva y escuchas un suave clip-clop. ¡Entre los árboles aparece una magnífica criatura con una melena ondulante!','¡En el ___, ___ blancas y esponjosas mordisquean ___ bajo el sol!','La hierba alta cruje. Dos orejas con rayas blancas y negras asoman. ¡Qué patrón tan llamativo!','Un ___ gentil se sienta comiendo una ___ en lo alto de un ___.','Arriba en un eucalipto, alguien gris y esponjoso está durmiendo la siesta. ¡Deletrea su nombre!'],
  fr: ['La jungle vous accueille','Tu entres dans la jungle et entends un doux clip-clop. À travers les arbres, une magnifique créature à la crinière flottante apparaît !','Dans le ___, de douces ___ blanches grignotent de l\\\'___ au soleil !','Les hautes herbes bruissent. Deux oreilles à rayures noires et blanches apparaissent. Quel motif saisissant !','Un ___ gentil est assis et mange une ___ tout en haut d\\\'un ___.','Tout en haut d\\\'un eucalyptus, quelqu\\\'un de gris et duveteux fait la sieste. Épelle son nom !'],
  it: ['La giungla ti dà il benvenuto','Entri nella giungla e senti un dolce clip-clop. Tra gli alberi appare una magnifica creatura con una criniera fluente!','Nel ___, soffici ___ bianche mordicchiano ___ al sole!','L\\\'erba alta fruscia. Due orecchie con strisce bianche e nere spuntano. Che motivo sorprendente!','Un ___ gentile siede mangiando una ___ in alto su un ___.','In alto su un eucalipto, qualcuno di grigio e morbido sta facendo un pisolino. Sillabia il suo nome!'],
  ja: ['ジャングルへようこそ','ジャングルにはいると、やさしいパカパカというおとがきこえます。きのあいだから、ながれるたてがみのすばらしいいきものがあらわれました！','___のうえで、ふわふわのしろい___がひなたで___をかじっています！','たかいくさがカサカサなります。くろとしろのしまもようのみみがふたつとびだしました。なんてめだつもようでしょう！','やさしい___が___のたかいところで___をたべてすわっています。','ユーカリのきのたかいところで、はいいろでふわふわのだれかがおひるねしています。なまえをつづろう！'],
  la: ['Silva te salutat','In silvam intras et lenem sonum audis. Per arbores, magnifica creatura cum iuba fluente apparet!','In ___, molles albae ___ in sole ___ rodunt!','Alta herba susurrat. Duae aures cum striis nigris et albis apparent. Quam insignis forma!','Mitis ___ sedens ___ in alto ___ edit.','In alto in arbore eucalypti, aliquis canus et mollis dormitat. Nomen litteris pone!'],
  nl: ['De jungle verwelkomt je','Je stapt de jungle in en hoort een zacht klip-klop geluid. Tussen de bomen verschijnt een prachtig wezen met een wapperende manen!','Op de ___ knabbelen donzige witte ___ aan ___ in de zon!','Het hoge gras ritselt. Twee oren met zwart-witte strepen komen tevoorschijn. Wat een opvallend patroon!','Een lieve ___ zit een ___ te eten hoog in een ___.','Hoog in een eucalyptusboom doet iemand grijs en donzig een dutje. Spel hun naam!'],
  pl: ['Dżungla cię wita','Wchodzisz do dżungli i słyszysz delikatny stukot kopyt. Między drzewami pojawia się wspaniałe stworzenie z powiewającą grzywą!','Na ___ puszyste białe ___ skubią ___ w słońcu!','Wysoka trawa szeleści. Dwa uszy z czarno-białymi paskami wyskakują. Co za uderzający wzór!','Łagodny ___ siedzi jedząc ___ wysoko na ___.','Wysoko na drzewie eukaliptusowym ktoś szary i puszysty drzemie. Przeliteruj imię!'],
  pt: ['A selva te dá as boas-vindas','Você entra na selva e ouve um suave clip-clop. Entre as árvores, uma magnífica criatura com uma crina esvoaçante aparece!','No ___, ___ brancos e fofinhos mordiscam ___ ao sol!','A grama alta farfalha. Duas orelhas com listras pretas e brancas aparecem. Que padrão marcante!','Um ___ gentil está sentado comendo uma ___ no alto de um ___.','Lá no alto de um eucalipto, alguém cinza e fofinho está tirando uma soneca. Soletre o nome!'],
  tr: ['Orman Seni Karşılıyor','Ormana giriyorsun ve nazik bir tıkırtı duyuyorsun. Ağaçların arasından, dalgalanan yeleli muhteşem bir yaratık belirir!','___\'da, kabarık beyaz ___ güneşte ___ kemiriyor!','Uzun otlar hışırdıyor. Siyah beyaz çizgili iki kulak beliriyor. Ne çarpıcı bir desen!','Nazik bir ___ yüksekte bir ___\'da ___ yiyerek oturuyor.','Okaliptüs ağacının tepesinde, gri ve tüylü biri şekerleme yapıyor. İsmini hecele!'],
  zh: ['丛林欢迎你','你走进丛林，听到轻柔的嗒嗒声。树丛间出现了一只有着飘逸鬃毛的壮丽生物！','在___上，毛茸茸的白色___在阳光下啃着___！','高高的草丛沙沙作响。两只黑白条纹的耳朵冒了出来。多么醒目的花纹！','一只温柔的___坐在高高的___上吃着___。','在桉树高处，一个灰色毛茸茸的家伙正在打盹。拼写它的名字！'],
};

// Story 8: bearHungry
S['bearHungry'] = {
  ar: ['بطن الدب الجائع','بطن الدب يقرقر! يفتح باب المطبخ. شيء دافئ وذهبي خرج للتو من الفرن!','في ___، لاحظ الدب ___ من الفاكهة البنفسجية تنمو على ___!','عشاء الدب المفضل في الفرن، مع جبن ذائب يغلي على الوجه!','بوب! بعض ___ قفز من المحمصة، ___ ومقرمش، مثالي مع ___!','للتحلية، يقطف الدب فاكهة حلوة استوائية برتقالية وعصارية من الداخل. يا لها من وليمة!'],
  da: ['Bjørns sultne mave','Bjørns mave rumler! Han åbner køkkendøren. Noget varmt og gyldent er lige kommet ud af ovnen!','I ___ ser Bjørn en ___ med lilla frugt der vokser på en ___!','Bjørns absolutte yndlingsmiddag er i ovnen, med smeltet ost der bobler ovenpå!','Pop! Noget ___ poppede op fra brødristeren, ___ og sprødt, perfekt med ___!','Til dessert plukker Bjørn en sød, tropisk frugt der er orange og saftig indeni. Sikke en fest!'],
  de: ['Bärs hungriger Bauch','Bärs Bauch knurrt! Er öffnet die Küchentür. Etwas Warmes und Goldenes kam gerade aus dem Ofen!','Im ___ entdeckt Bär ein ___ lila Früchte auf einem ___!','Bärs absolutes Lieblingsessen ist im Ofen, mit geschmolzenem Käse der oben blubbert!','Pop! Etwas ___ sprang aus dem Toaster, ___ und knusprig, perfekt mit ___!','Zum Nachtisch pflückt Bär eine süße, tropische Frucht die innen orange und saftig ist. Was für ein Fest!'],
  es: ['La barriguita hambrienta de Oso','¡La barriga de Oso está rugiendo! Abre la puerta de la cocina. ¡Algo cálido y dorado acaba de salir del horno!','¡En el ___, Oso ve un ___ de fruta morada creciendo en un ___!','¡La cena favorita de Oso está en el horno, con queso derretido burbujeando encima!','¡Pop! Algo de ___ saltó de la tostadora, ___ y crujiente, ¡perfecto con ___!','De postre, Oso recoge una fruta dulce y tropical que es naranja y jugosa por dentro. ¡Qué festín!'],
  fr: ['Le ventre affamé d\\\'Ours','Le ventre d\\\'Ours gargouille ! Il ouvre la porte de la cuisine. Quelque chose de chaud et doré vient de sortir du four !','Dans le ___, Ours repère un ___ de fruits violets poussant sur un ___ !','Le dîner préféré d\\\'Ours est dans le four, avec du fromage fondu qui bouillonne !','Pop ! Du ___ a sauté du grille-pain, ___ et croustillant, parfait avec ___ !','Pour le dessert, Ours cueille un fruit doux et tropical qui est orange et juteux à l\\\'intérieur. Quel festin !'],
  it: ['La pancina affamata di Orso','La pancia di Orso brontola! Apre la porta della cucina. Qualcosa di caldo e dorato è appena uscito dal forno!','Nel ___, Orso vede un ___ di frutta viola che cresce su un ___!','La cena preferita di Orso è nel forno, con formaggio fuso che gorgoglia sopra!','Pop! Del ___ è saltato fuori dal tostapane, ___ e croccante, perfetto con ___!','Per dessert, Orso raccoglie un frutto dolce e tropicale arancione e succoso dentro. Che banchetto!'],
  ja: ['くまのおなかがぺこぺこ','くまのおなかがグーグーなっている！だいどころのドアをあけます。あたたかくてきんいろのなにかがオーブンからでてきたよ！','___のなかで、くまは___のむらさきのくだものが___にそだっているのをみつけました！','くまのだいすきなゆうごはんがオーブンのなかに、とけたチーズがぶくぶくのっています！','ポン！___がトースターからとびだした、___でカリカリ、___といっしょにかんぺき！','デザートに、くまはあまくてトロピカルなくだものをえらびます。なかはオレンジいろでジューシー。なんてごちそう！'],
  la: ['Venter esuriens Ursi','Venter Ursi murmurat! Ianuam culinae aperit. Aliquid calidum et aureum modo de furno exiit!','In ___, Ursus ___ fructuum purpureorum in ___ crescentem videt!','Cena dilectissima Ursi in furno est, cum caseo liquefacto supra bulliente!','Pop! Aliquid ___ de torrente panis exsilivit, ___ et fragile, perfectum cum ___!','Pro mensa secunda, Ursus dulcem fructum tropicum qui intus aurantiacus et sucosus est carpit. Quae epulae!'],
  nl: ['Beers hongerige buik','Beers buik rommelt! Hij opent de keukendeur. Iets warms en goudens kwam net uit de oven!','In de ___ ziet Beer een ___ paars fruit groeien aan een ___!','Beers favoriete avondeten staat in de oven, met gesmolten kaas die erboven borrelt!','Pop! Wat ___ sprong uit de broodrooster, ___ en knapperig, perfect met ___!','Als toetje plukt Beer een zoet, tropisch fruit dat van binnen oranje en sappig is. Wat een feest!'],
  pl: ['Głodny brzuszek Misia','Brzuch Misia burczy! Otwiera drzwi kuchni. Coś ciepłego i złotego właśnie wyszło z pieca!','W ___ Miś widzi ___ fioletowych owoców rosnących na ___!','Ulubiona kolacja Misia jest w piekarniku, z rozpuszczonym serem bulgoczącym na wierzchu!','Pop! Trochę ___ wyskoczyło z tostera, ___ i chrupiące, idealne z ___!','Na deser Miś zrywa słodki, tropikalny owoc, który w środku jest pomarańczowy i soczysty. Co za uczta!'],
  pt: ['A barriguinha faminta do Urso','A barriga do Urso está roncando! Ele abre a porta da cozinha. Algo quente e dourado acabou de sair do forno!','No ___, Urso vê um ___ de frutas roxas crescendo em um ___!','O jantar favorito do Urso está no forno, com queijo derretido borbulhando por cima!','Pop! Um pouco de ___ saltou da torradeira, ___ e crocante, perfeito com ___!','De sobremesa, Urso pega uma fruta doce e tropical que é laranja e suculenta por dentro. Que banquete!'],
  tr: ['Ayının Aç Karnı','Ayının karnı gurulduyor! Mutfak kapısını açıyor. Fırından sıcak ve altın rengi bir şey çıktı!','___\'da Ayı, ___\'da yetişen bir ___ mor meyve görüyor!','Ayının en sevdiği yemek fırında, üstünde erimiş peynir fokurdayarak!','Pop! Biraz ___ tost makinesinden fırladı, ___ ve çıtır, ___ ile mükemmel!','Tatlı olarak Ayı tatlı, tropik bir meyve toplar — içi turuncu ve sulu. Ne güzel bir ziyafet!'],
  zh: ['小熊的饿肚子','小熊的肚子咕咕叫！他打开厨房门。温暖金黄的东西刚从烤箱里出来！','在___里，小熊看到一___紫色水果长在___上！','小熊最爱的晚餐在烤箱里，融化的奶酪在上面冒泡！','砰！一些___从烤面包机里弹出来，___又脆，配___完美！','甜点时间，小熊摘了一个甜甜的热带水果，里面是橙色多汁的。好丰盛的大餐！'],
};

// Story 9: enchantedCastle
S['enchantedCastle'] = {
  ar: ['القلعة المسحورة','فتحت كتاب قصص سحري وسُحبت إلى الداخل! أمامك مبنى عظيم بأبراج عالية. ما هو؟','في الداخل، ___ ودود بقشور لامعة يرحب بك. ينفث ___ دافئاً، لكن لا تقلق، إنه ___!','المخلوق يقودك إلى قاعة العرش، حيث أحكم وألطف حاكم في كل الأرض يبتسم بدفء.','لإيجاد طريق العودة، اعبر ___. اتبع ___ عبر ___ المرقط.','في قلب كل شيء، دوامة من الشرارات تظهر. الكتاب يتوهج. هذه القوة ستأخذك إلى المنزل!'],
  da: ['Det fortryllede slot','Du åbner en magisk historiebog og trækkes lige ind! Foran dig står en storslået bygning med høje tårne. Hvad er det?','Indeni hilser en venlig ___ med glimtende skæl på dig. Den puster varm ___, men rolig, den er ___!','Væsnet fører dig til tronsalen, hvor den klogeste og venligste hersker i hele landet smiler varmt.','For at finde hjem, rejs gennem ___. Følg ___ gennem det plettet ___.','I hjertet af det hele dukker en hvirvel af gnister op. Bogen lyser. Denne kraft vil tage dig hjem!'],
  de: ['Die verzauberte Burg','Du öffnest ein magisches Märchenbuch und wirst hineingezogen! Vor dir steht ein prächtiges Gebäude mit hohen Türmen. Was ist es?','Drinnen begrüßt dich ein freundlicher ___ mit schimmernden Schuppen. Er atmet warmes ___, aber keine Sorge, es ist ___!','Das Wesen führt dich zum Thronsaal, wo der weiseste und freundlichste Herrscher des ganzen Landes warm lächelt.','Um nach Hause zu finden, reise durch den ___. Folge dem ___ durch das gefleckte ___.','Im Herzen von allem erscheint ein Wirbel von Funken. Das Buch leuchtet. Diese Kraft bringt dich nach Hause!'],
  es: ['El castillo encantado','¡Abres un libro de cuentos mágico y te absorbe! Ante ti se alza un edificio grandioso con torres altas. ¿Qué es?','Dentro, un ___ amigable con escamas brillantes te saluda. Respira ___ cálido, ¡pero no te preocupes, es ___!','La criatura te lleva a la sala del trono, donde el gobernante más sabio y amable de toda la tierra sonríe cálidamente.','Para encontrar el camino a casa, viaja por el ___. Sigue el ___ por el ___ moteado.','En el corazón de todo, aparece un remolino de destellos. El libro brilla. ¡Este poder te llevará a casa!'],
  fr: ['Le château enchanté','Tu ouvres un livre de contes magique et tu es aspiré dedans ! Devant toi se dresse un grand bâtiment avec de hautes tours. Qu\\\'est-ce que c\\\'est ?','À l\\\'intérieur, un ___ amical aux écailles chatoyantes t\\\'accueille. Il souffle du ___ chaud, mais ne t\\\'inquiète pas, il est ___ !','La créature te conduit à la salle du trône, où le souverain le plus sage et le plus gentil sourit chaleureusement.','Pour trouver ton chemin, voyage à travers le ___. Suis le ___ à travers le ___ tacheté.','Au cœur de tout, un tourbillon d\\\'étincelles apparaît. Le livre brille. Ce pouvoir te ramènera chez toi !'],
  it: ['Il castello incantato','Apri un libro di fiabe magico e vieni risucchiato dentro! Davanti a te si erge un grande edificio con alte torri. Cos\\\'è?','Dentro, un ___ amichevole con squame luccicanti ti saluta. Soffia ___ caldo, ma non preoccuparti, è ___!','La creatura ti conduce alla sala del trono, dove il sovrano più saggio e gentile di tutta la terra sorride calorosamente.','Per trovare la via di casa, attraversa il ___. Segui il ___ attraverso il ___ screziato.','Nel cuore di tutto, appare un vortice di scintille. Il libro risplende. Questo potere ti porterà a casa!'],
  ja: ['まほうのおしろ','まほうのえほんをひらくと、なかにすいこまれた！めのまえに、たかいとうのあるりっぱなたてものがあります。なにかな？','なかでは、きらきらのうろこをもったやさしい___がむかえてくれます。あたたかい___をふきますが、しんぱいしないで、___だよ！','そのいきものがおうざのまにつれていきます。いちばんかしこくてやさしいおさまがにこにこしています。','おうちへのみちをみつけるには、___をたびしよう。まだらな___をとおって___についていこう。','すべてのちゅうしんに、きらめきのうずがあらわれます。えほんがひかります。このちからがおうちにつれてかえってくれる！'],
  la: ['Arx Incantata','Librum fabulosum magicum aperis et intus traharis! Ante te stat magnificum aedificium cum altis turribus. Quid est?','Intus, amicabilis ___ squamis fulgens te salutat. Calidum ___ spirat, sed noli timere, ___ est!','Creatura te ad aulam throni ducit, ubi sapientissimus et benignissimus rector totius terrae blande subridet.','Ut viam domum invenias, per ___ iter fac. ___ per maculatum ___ sequere.','In corde omnium, vortex scintillarum apparet. Liber lucet. Haec vis te domum feret!'],
  nl: ['Het betoverde kasteel','Je opent een magisch sprookjesboek en wordt er recht in getrokken! Voor je staat een groots gebouw met hoge torens. Wat is het?','Binnen begroet een vriendelijke ___ met glinsterende schubben je. Het blaast warme ___, maar maak je geen zorgen, het is ___!','Het wezen leidt je naar de troonzaal, waar de wijste en vriendelijkste heerser van het hele land warm glimlacht.','Om de weg naar huis te vinden, reis door het ___. Volg de ___ door het gevlekte ___.','In het hart van alles verschijnt een werveling van vonken. Het boek gloeit. Deze kracht brengt je naar huis!'],
  pl: ['Zaczarowany zamek','Otwierasz magiczną księgę i zostajesz wciągnięty do środka! Przed tobą stoi wspaniały budynek z wysokimi wieżami. Co to jest?','Wewnątrz wita cię przyjazny ___ z błyszczącymi łuskami. Zieje ciepłym ___, ale nie martw się, jest ___!','Stworzenie prowadzi cię do sali tronowej, gdzie najmądrzejszy i najżyczliwszy władca ciepło się uśmiecha.','Aby znaleźć drogę do domu, podróżuj przez ___. Podążaj za ___ przez cętkowany ___.','W sercu wszystkiego pojawia się wir iskier. Księga świeci. Ta moc zabierze cię do domu!'],
  pt: ['O castelo encantado','Você abre um livro de contos mágico e é puxado para dentro! Diante de você está um grande edifício com torres altas. O que é?','Dentro, um ___ amigável com escamas brilhantes te cumprimenta. Ele sopra ___ quente, mas não se preocupe, é ___!','A criatura te leva à sala do trono, onde o governante mais sábio e gentil de toda a terra sorri calorosamente.','Para encontrar o caminho de casa, viaje pelo ___. Siga o ___ pelo ___ salpicado.','No coração de tudo, um redemoinho de brilhos aparece. O livro brilha. Esse poder vai te levar para casa!'],
  tr: ['Büyülü Kale','Sihirli bir hikâye kitabı açıyorsun ve içine çekiliyorsun! Önünde yüksek kuleleri olan büyük bir bina duruyor. Ne bu?','İçeride, parlak pullu dostça bir ___ seni karşılıyor. Sıcak ___ üflüyor ama endişelenme, o ___!','Yaratık seni taht odasına götürüyor, tüm ülkenin en bilge ve en nazik hükümdarı sıcacık gülümsüyor.','Eve dönüş yolunu bulmak için ___\'dan geç. Benekli ___\'dan ___ takip et.','Her şeyin kalbinde, bir pırıltı girdabı belirir. Kitap parlıyor. Bu güç seni eve götürecek!'],
  zh: ['魔法城堡','你打开一本魔法故事书，被吸了进去！面前矗立着一座有高塔的宏伟建筑。它是什么？','里面，一只有闪亮鳞片的友好___迎接你。它吐出温暖的___，但别担心，它是___的！','这个生物带你来到王座大厅，最聪明最善良的统治者温暖地微笑着。','要找到回家的路，穿过___。跟着___穿过斑驳的___。','在一切的中心，一阵闪光旋涡出现了。书发出光芒。这股力量会带你回家！'],
};

